// ============================================================
// PREPARE escalation data
// ============================================================
const input = $input.first().json;
const tenant = input.tenant;

if (!tenant || !tenant.business_id) throw new Error('Missing tenant.business_id');
if (!tenant.admin_whatsapp) throw new Error('Missing tenant.admin_whatsapp');

const reason = input.reason || 'customer_request';
const customerMsg = input.customer_message || '';
const contextSummary = input.context_summary || '';

const reasonLabels = {
  customer_request:  'طلب العميل التحدث مع موظف',
  complaint:         'شكوى من العميل',
  out_of_scope:      'استفسار خارج نطاق البوت',
  negative_sentiment:'حالة عاطفية سلبية',
  technical_issue:   'مشكلة تقنية',
  vip_priority:      'عميل VIP',
  payment_issue:     'مشكلة في الدفع',
  order_issue:       'مشكلة في الطلب'
};

const reasonText = reasonLabels[reason] || reason;
const now = new Date();
const dateStr = now.toISOString().slice(0,10).replace(/-/g,'');
const escalationId = `ESC_${dateStr}_${Math.floor(Math.random() * 90000) + 10000}`;

const adminAlert = `🚨 *تنبيه تصعيد — ${tenant.business_name}*\n\n🆔 رقم التصعيد: ${escalationId}\n👤 العميل: ${input.customer?.name || 'غير محدد'}\n📞 الرقم: ${input.customer?.phone || 'غير محدد'}\n\n💬 آخر رسالة:\n${customerMsg.slice(0, 250)}\n\n📌 السبب: ${reasonText}\n\n${contextSummary ? '📋 سياق:\n' + contextSummary : ''}\n\n🕐 ${now.toISOString().slice(0,19).replace('T',' ')}\n\n⚠️ تواصل مع العميل في أسرع وقت.`;

const customerReply = `لحظة من فضلك يا فندم 🙏\nهحوّلك دلوقتي لزميل من فريق *${tenant.business_name}* يساعدك بشكل أفضل.\nهيتواصل معاك في أقرب وقت ✨`;

return {
  json: {
    business_id:      tenant.business_id,
    order_id:         tenant.order_id || '',
    instance_name:    tenant.instance_name || '',
    admin_whatsapp:   tenant.admin_whatsapp,
    escalation_id:    escalationId,
    conversation_id:  input.conversation_id || '',
    customer:         input.customer || {},
    reason:           reason,
    reason_text:      reasonText,
    customer_message: customerMsg,
    context_summary:  contextSummary,
    admin_alert:      adminAlert,
    customer_reply:   customerReply,
    timestamp:        now.toISOString()
  }
};

return {
  json: {
    success: true,
    escalation_id:  $('ESCALATION_PREPARE').first().json.escalation_id,
    customer_reply: $('ESCALATION_PREPARE').first().json.customer_reply,
    reason:         $('ESCALATION_PREPARE').first().json.reason
  }
};
